import{_ as a,o as t,c as n,j as r,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"情书","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/情书.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/情书.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/情书.md"};function b(l,e,i,_,p,c){return t(),n("div",null,[...e[0]||(e[0]=[r("h1",{id:"情书",tabindex:"-1"},[s("情书 "),r("a",{class:"header-anchor",href:"#情书","aria-label":'Permalink to "情书"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌039")])])],-1),o('<h1 id="情书-1" tabindex="-1">情书 <a class="header-anchor" href="#情书-1" aria-label="Permalink to &quot;情书&quot;">​</a></h1><p>【情书】<br> 类型：武器/拳套<br> B+2000<br> 它穿过熙熙攘攘的人群，穿过桌椅与窗户的缝隙，穿过不理解的层层阻碍，最终抵达你的身边……<br> 接受与否，这份情感都已经传递。<br> 这是一双红黑色的露指手套，每只手套上的绳子都精细的绑成了蝴蝶结的样子，每一拳都是一份沉重的爱意。<br> 【情书】拥有6点附加成功 造成伤害由冲击转化为严重<br> 伤害类型：基于手部天生武器<br> 体积：1<br> 特性：【爱与恨】【最后的情书】【幕后的守望】<br> 【爱与恨】：未曾说出口的真心，爱与悔恨纷沓而至<br> 你的攻击将附带攻击伤害等量魅惑点数<br> 对于拥有对你所造成魅惑点数的目标，你的攻击检定加骰提升一级，至多8加骰<br> 但对于陷入你造成迷情效果或毁灭性的目标，该目标将优先攻击自己，其次是其他拥有你所造成魅惑点数的目标。<br> 【幕后的守望】：暴力，是否是爱呢<br> 当你在战斗中佩戴【情书】每持续一轮，那么其上就会有一枚红黑色的蝴蝶绽放，这会使得你攻击时额外获得2点威猛，上限2轮，战斗结束清空<br> 【最后的情书】：我还想拍，你的笑容<br> 你可选择打断性的调用下回合的一个标准动作进行一次类招架动作【反击】，受到攻击时立即进行反击，反击伤害等同于获得的招架伤害抵销数，这些伤害不可豁免，但可以被减免、吸收。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=a(d,[["render",b]]);export{f as __pageData,m as default};
